import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"上传日志","description":"如何上传日志以进行疑难解答。","frontmatter":{"title":"上传日志","description":"如何上传日志以进行疑难解答。","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"zh_cn/players/troubleshooting/uploading-logs.md","filePath":"translated/zh_cn/players/troubleshooting/uploading-logs.md","lastUpdated":1772272927000}`);var a={name:`zh_cn/players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">上传日志 <a class="header-anchor" href="#h1" aria-label="Permalink to “上传日志”">​</a></h1><p>在进行疑难解答时，通常需要提供日志以帮助寻找问题的原因。</p><h2 id="why-should-i-upload-logs" tabindex="-1">为什么我应该上传日志？ <a class="header-anchor" href="#why-should-i-upload-logs" aria-label="Permalink to “为什么我应该上传日志？”">​</a></h2><p>相比直接在聊天或论坛帖子中粘贴日志，上传日志能让他人更快速地协助您排查问题。 此外，您无需复制粘贴即可与他人分享日志。</p><p>部分粘贴网站还提供日志语法高亮功能，便于阅读，并可能自动屏蔽敏感信息，例如您的用户名或系统信息。</p><h2 id="crash-reports" tabindex="-1">崩溃报告 <a class="header-anchor" href="#crash-reports" aria-label="Permalink to “崩溃报告”">​</a></h2><p>游戏崩溃时会自动生成崩溃报告。 崩溃报告只包含崩溃信息，不包含实际的游戏日志。 崩溃报告位于游戏目录中的 <code>crash-reports</code> 文件夹中。</p><p>有关崩溃报告的更多信息，请参阅<a href="./crash-reports">崩溃报告</a>章节。</p><h2 id="locating-logs" tabindex="-1">找到日志 <a class="header-anchor" href="#locating-logs" aria-label="Permalink to “找到日志”">​</a></h2><p>本指南涵盖了官方 Minecraft 启动器（通常称为“原版启动器”）——对于第三方启动器，你应该参阅其文档。</p><p>日志位于游戏目录下的 <code>logs</code> 文件夹中，游戏目录可以在以下位置找到，具体取决于你的操作系统：</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language-text active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>最新的日志文件名为 <code>latest.log</code>，先前的日志使用命名格式 <code>yyyy-mm-dd_number.log.gz</code>。</p><h2 id="uploading-logs-online" tabindex="-1">在线上传日志 <a class="header-anchor" href="#uploading-logs-online" aria-label="Permalink to “在线上传日志”">​</a></h2><p>日志可以上传到各种服务，例如：</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};